import type { InvoiceLineDto } from '../services/bh/models';

export function activatesLineDiscount(
  patch: Partial<InvoiceLineDto>,
  line: InvoiceLineDto,
): boolean {
  const nextRate = patch.discountRate !== undefined
    ? Number(patch.discountRate) || 0
    : Number(line.discountRate) || 0;
  const nextAmount = patch.discountAmount !== undefined
    ? Number(patch.discountAmount) || 0
    : Number(line.discountAmount) || 0;
  if (nextRate > 0) return true;
  return nextRate === 0 && nextAmount > 0;
}

export function headerDiscountFooterActive(
  useHeaderDiscount: boolean,
  headerDiscountAmount: number,
): boolean {
  return useHeaderDiscount || headerDiscountAmount > 0;
}

export function needsHeaderDiscountClearConfirm(
  patch: Partial<InvoiceLineDto>,
  line: InvoiceLineDto,
  useHeaderDiscount: boolean,
  headerDiscountAmount: number,
): boolean {
  return activatesLineDiscount(patch, line)
    && headerDiscountFooterActive(useHeaderDiscount, headerDiscountAmount);
}
